CREATE VIEW lca.district_geo AS
 SELECT d.district_id,
    d.district_name,
    d.trips_per_day,
    d.km_per_trip,
    d.homeoffice_pct,
    d.auto_besetzung,
    d.split_fuss,
    d.split_rad,
    d.split_opnv,
    d.split_auto,
    d.opnv_share_ubahn,
    d.opnv_share_sbahn,
    d.opnv_share_bus,
    d.opnv_share_tram,
    d.auto_share_benzin,
    d.auto_share_diesel,
    d.auto_share_phev,
    d.auto_share_elektro,
    d.population,
    d.household_size,
    d.car_per_household,
    v.geom,
    v.sb_name,
    v.flaeche_qm
   FROM (lca.district_base d
     JOIN lca.vablock_stadtbezirk v ON (((v.sb_nummer)::integer = d.district_id)));


